SELECT m.*, mem.member_nm AS member_nm, cd_pm.code_label AS pay_method_type_cd_nm FROM od_pay_method m LEFT JOIN mb_member mem ON mem.member_id = m.member_id LEFT JOIN sy_code cd_pm ON cd_pm.code_grp = 'PAY_METHOD' AND cd_pm.code_value = m.pay_method_type_cd
ORDER BY m.pay_method_id ASC ORDER BY m.pay_method_id DESC ORDER BY m.pay_method_nm ASC ORDER BY m.pay_method_nm DESC ORDER BY m.reg_date ASC ORDER BY m.reg_date DESC ORDER BY m.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

